(function(global){
function enc(s){return String(s).replace(/\\/g,'\\\\').replace(/\(/g,'\\(').replace(/\)/g,'\\)').replace(/[\u0400-\u04FF]/g,function(ch){return ch;});}
class jsPDF{constructor(opts={}){this.orientation=opts.orientation||'p';this.unit=opts.unit||'pt';this.format=opts.format||'a4';this.w=this.orientation==='landscape'?841.89:595.28;this.h=this.orientation==='landscape'?595.28:841.89;this.pages=[[]];this.fontSize=10;this.x=40;this.y=40}setFontSize(n){this.fontSize=n;return this}setFont(){return this}text(txt,x,y,opt={}){this.pages[this.pages.length-1].push({type:'text',txt:String(txt),x,y,size:this.fontSize,align:opt.align||'left'});return this}line(x1,y1,x2,y2){this.pages[this.pages.length-1].push({type:'line',x1,y1,x2,y2});return this}rect(x,y,w,h){this.pages[this.pages.length-1].push({type:'rect',x,y,w,h});return this}addPage(){this.pages.push([]);return this}splitTextToSize(txt,max){const chars=Math.max(8,Math.floor(max/(this.fontSize*.48)));const words=String(txt).split(' ');const lines=[];let line='';words.forEach(w=>{if((line+' '+w).trim().length>chars){if(line)lines.push(line);line=w}else line=(line+' '+w).trim()});if(line)lines.push(line);return lines}save(name='document.pdf'){const blob=this.output('blob');const a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download=name;document.body.appendChild(a);a.click();setTimeout(()=>{URL.revokeObjectURL(a.href);a.remove()},1000)}output(type='blob'){let objects=[];let pagesKids=[];const add=s=>{objects.push(s);return objects.length};const fontId=add('<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica /Encoding /WinAnsiEncoding >>');this.pages.forEach(page=>{let stream='';page.forEach(o=>{if(o.type==='text'){let x=o.x;if(o.align==='center')x=o.x-String(o.txt).length*o.size*.25;if(o.align==='right')x=o.x-String(o.txt).length*o.size*.5;stream+=`BT /F1 ${o.size} Tf ${x.toFixed(2)} ${(this.h-o.y).toFixed(2)} Td (${enc(translit(o.txt))}) Tj ET\n`}if(o.type==='line'){stream+=`${o.x1} ${this.h-o.y1} m ${o.x2} ${this.h-o.y2} l S\n`}if(o.type==='rect'){stream+=`${o.x} ${this.h-o.y-o.h} ${o.w} ${o.h} re S\n`}});const sid=add(`<< /Length ${stream.length} >>\nstream\n${stream}endstream`);const pid=add(`<< /Type /Page /Parent 0 0 R /MediaBox [0 0 ${this.w} ${this.h}] /Resources << /Font << /F1 ${fontId} 0 R >> >> /Contents ${sid} 0 R >>`);pagesKids.push(pid)});const pagesId=add('');const catalogId=add(`<< /Type /Catalog /Pages ${pagesId} 0 R >>`);objects[pagesId-1]=`<< /Type /Pages /Kids [${pagesKids.map(id=>id+' 0 R').join(' ')}] /Count ${pagesKids.length} >>`;objects=objects.map(s=>s.replace('/Parent 0 0 R',`/Parent ${pagesId} 0 R`));let pdf='%PDF-1.4\n';const offsets=[0];objects.forEach((o,i)=>{offsets.push(pdf.length);pdf+=`${i+1} 0 obj\n${o}\nendobj\n`});const xref=pdf.length;pdf+=`xref\n0 ${objects.length+1}\n0000000000 65535 f \n`;for(let i=1;i<offsets.length;i++)pdf+=String(offsets[i]).padStart(10,'0')+' 00000 n \n';pdf+=`trailer << /Size ${objects.length+1} /Root ${catalogId} 0 R >>\nstartxref\n${xref}\n%%EOF`;return new Blob([pdf],{type:'application/pdf'})}}
function translit(s){const map={А:'A',Б:'B',В:'V',Г:'H',Ґ:'G',Д:'D',Е:'E',Є:'Ye',Ж:'Zh',З:'Z',И:'Y',І:'I',Ї:'Yi',Й:'Y',К:'K',Л:'L',М:'M',Н:'N',О:'O',П:'P',Р:'R',С:'S',Т:'T',У:'U',Ф:'F',Х:'Kh',Ц:'Ts',Ч:'Ch',Ш:'Sh',Щ:'Shch',Ь:'',Ю:'Yu',Я:'Ya',а:'a',б:'b',в:'v',г:'h',ґ:'g',д:'d',е:'e',є:'ye',ж:'zh',з:'z',и:'y',і:'i',ї:'yi',й:'y',к:'k',л:'l',м:'m',н:'n',о:'o',п:'p',р:'r',с:'s',т:'t',у:'u',ф:'f',х:'kh',ц:'ts',ч:'ch',ш:'sh',щ:'shch',ь:'',ю:'yu',я:'ya','×':'x','№':'#'};return String(s).replace(/[А-Яа-яІіЇїЄєҐґ×№]/g,ch=>map[ch]??ch)}
global.jspdf={jsPDF};})(window);
